from django.http import HttpResponse, HttpResponseRedirect
from django.views.decorators.csrf import csrf_exempt
import xml.etree.ElementTree as ET

def parse_saml_response(saml_response):
    root = ET.fromstring(saml_response)
    namespace = {'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
                 'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'}
    
    # Basic XML structure validation
    if root.tag != '{' + namespace['samlp'] + '}Response':
        raise ValueError("Invalid SAML response structure")
    
    assertion = root.find('.//{' + namespace['saml'] + '}Assertion')
    if assertion is None:
        raise ValueError("No Assertion found in the SAML response")
    
    name_id = assertion.find('.//{' + namespace['saml'] + '}NameID').text
    attributes = {}
    for attr_statement in assertion.findall('.//{' + namespace['saml'] + '}AttributeStatement'):
        for attribute in attr_statement.findall('.//{' + namespace['saml'] + '}Attribute'):
            attr_name = attribute.get('Name')
            attr_values = [value.text for value in attribute.findall('.//{' + namespace['saml'] + '}AttributeValue')]
            attributes[attr_name] = attr_values
    
    return name_id, attributes

